export function makeStrictEnum<T extends Record<PropertyKey, string | number>>(definition: T): T {
  return new Proxy(definition, {
    get(target, property) {
      if (property in target) {
        return target[property]
      }
      if (allowList.has(property)) {
        return undefined
      }
      throw new TypeError(`Invalid enum value: ${String(property)}`)
    },
  })
}

export function getCommandWithExecutor(command: string): string {
  // if current prisma bin is from a global dir
  if (isCurrentBinInstalledGlobally()) {
    // do nothing!
    return command
  } else {
    // When running in npx, npm puts this package into a /_npx/ folder. Tested on Win, Mac, Linux
    const npxUsed = __dirname.includes('_npx')
    if (npxUsed) {
      return `npx ${command}`
    } else {
      return command
    }
  }
}

export function chmodPlusX(file: string): void {
  // Note: skip for windows as chmod does on exist there
  // and will error with `EACCES: permission denied`
  if (process.platform === 'win32') return

  const s = fs.statSync(file)
  const newMode = s.mode | 64 | 8 | 1
  if (s.mode === newMode) {
    debug(`Execution permissions of ${file} are fine`)
    return
  }
  const base8 = newMode.toString(8).slice(-3)
  debug(`Have to call chmodPlusX on ${file}`)
  fs.chmodSync(file, base8)
}

export function createDeferred<TValue = void>() {
  let resolve: (value: TValue) => void;
  let reject: (error: unknown) => void;
  const promise = new Promise<TValue>((res, rej) => {
    resolve = res;
    reject = rej;
  });

  return { promise, resolve: resolve!, reject: reject! };
}
export type Deferred<TValue> = ReturnType<typeof createDeferred<TValue>>;

